  • 中国房产是政策驱动 > 市场驱动 —— 读政策、留余量、不赌政策: 中国房产市场是政策驱动多于市场驱动的市场 —— 限购/限贷/限售/认房认贷/LPR/参考价/房产税/保交楼都是可随时启用或急转的政策工具,「读政策原文」是核心能力;但读政策是为了「判方向、留余量」,不

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**建立板块价值地图**:把城市分成板块/地段单元,标注每个板块的核心驱动 —— 产业就业(有没有大企业/园区)、交通(地铁/通勤时间)、配套(商业/医院)成熟度。inputs: 城市规划 + 地图;outputs: 板块价值排序。"
  "**核查规划(利好与利空都要查)**:到城市规划/自然资源部门官网查目标板块的规划 —— 地铁线路、学校、商业是否落地;同时查「利空规划」:垃圾站、变电站、高压线、高架。inputs: 规划部门公示;outputs: 规划利好/利空清单。"
  "**核查学区(如果板块靠学区溢价)**:确认目标板块对应的学校、最新的学区划片政策(多校划片/摇号)、入学年限要求 —— 学区政策是高 decay 项,会变。inputs: 教育局划片文件;outputs: 学区有效性判断。"
  "**读板块二手房流动性**:用贝壳研究院/找房平台看目标板块的二手房挂牌量、成交周期、带看量 —— 同城里挂牌量暴增、成交周期拉到 12 个月的板块,流动性已经在恶化。inputs: 贝壳研究院/平台数据;outputs: 板块流动性标签。"
  "**筛出短名单**:产业/交通/配套有支撑 + 规划无重大利空 + (如靠学区)学区有效 + 流动性未崩 —— 同时满足才进短名单。"
)
declare -a FAILURE_MODES=(
  "**把规划的「饼」算进估值**:触发原因 = 听信「这里要通地铁/建名校」;怎么避免 = 只把已出让土地、已开工的配套算数,规划利好打折看。Don't: 因为「规划有地铁」溢价买入,十年后地铁仍未动工,板块价值兑现遥遥无期。"
  "**买「睡城」当价值洼地**:触发原因 = 单价低误判为便宜;怎么避免 = 先看板块有没有产业就业,无产业不碰。"
  "**信中介的学区承诺**:触发原因 = 中介「保证能上 XX 学校」;怎么避免 = 查教育局最新划片文件原文,政策可变。"
  "**Decay risk**: medium —— 板块价值逻辑稳定,但学区政策、规划进度、板块流动性是 12 个月内会变的高频项。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-2-walkthrough"
fi
